import{c as e}from"./DSWU3toF.js";const o={async getMe(){return(await e.get("/nurses/me")).data},async getClinics(){return(await e.get("/nurses/clinics")).data},async selectStation(s){return(await e.put("/nurses/me/station",s)).data},async getStations(){return(await e.get("/nurses/stations")).data},async getAvailableWards(){return(await e.get("/nurses/wards")).data},async updateProfile(s){return(await e.put("/nurses/me",s)).data},async getWardPatients(s){return(await e.get("/nurses/ward-patients",{params:{clinic_id:s?.clinicId,ward:s?.ward}})).data},async getNotifications(){return(await e.get("/nurses/notifications")).data},async markNotificationRead(s){return(await e.put(`/nurses/notifications/${s}/read`)).data},async getPatientOrders(s){return(await e.get(`/nurses/patients/${s}/orders`)).data},async completeOrder(s){return(await e.put(`/nurses/orders/${s}/complete`)).data},async getPatientSBARNotes(s){return(await e.get(`/nurses/patients/${s}/sbar`)).data},async createSBARNote(s,t,n){return(await e.post(`/nurses/patients/${s}/sbar?admission_id=${t}`,n)).data}};export{o as n};
